// Normalize keys from workflow 1 or a direct webhook call
const input = $input.first().json;
const candidates = Array.isArray(input)
  ? input
  : [
      ...(input.new_file_keys || []),
      ...(input.modified_file_keys || []),
      ...(input.keys || []),
      ...(input.image_keys || [])
    ];

const allKeys = [...new Set(candidates
  .map(item => typeof item === 'string' ? item : (item.key || item.Key))
  .filter(Boolean))];
const textExts = /\.(json|txt|csv|md|tsv)$/i;
const imageExts = /\.(jpg|jpeg|png|webp)$/i;
const textKeys = allKeys.filter(key => textExts.test(key));
const imageKeys = allKeys.filter(key => imageExts.test(key));

const fs = require('fs');
fs.writeFileSync('/tmp/clean_batch.json', JSON.stringify(textKeys));

return {
  json: {
    batch_size: textKeys.length,
    image_files: imageKeys.length,
    all_keys: allKeys,
    text_keys: textKeys,
    image_keys: imageKeys
  }
};

// Build the validator batch from cleaner-local JSON paths
const item = $input.first().json;
const raw = typeof item === 'string' ? item : (item.stdout ?? '');
let report = {};
try { report = JSON.parse(raw); } catch (e) { report = {}; }

const files = Array.isArray(report.files) ? report.files : [];
const localJsonFiles = files
  .filter(file => file.status === 'success' && String(file.file).toLowerCase().endsWith('.json'))
  .map(file => file.file);
const fs = require('fs');
fs.writeFileSync('/tmp/validate_batch.json', JSON.stringify(localJsonFiles));

const prepared = $('Prepare Batch Files').first().json;
const exitFailed = Number(item.exitCode || 0) !== 0 || Boolean(item.error);
const cleaningErrors = (report.stats?.error || 0) + (exitFailed && !report.stats?.error ? 1 : 0);

return {
  json: {
    cleaning_report: report,
    cleaning_errors: cleaningErrors,
    local_json_files: localJsonFiles,
    all_keys: prepared.all_keys || [],
    image_keys: prepared.image_keys || []
  }
};

// Merge cleaner and validator results while preserving embedding keys
const item = $input.first().json;
const raw = typeof item === 'string' ? item : (item.stdout ?? '');
let report = {};
try { report = JSON.parse(raw); } catch (e) { report = {}; }

const validation = report.stats || {};
const prepared = $('Prepare Validation Batch').first().json;
const exitFailed = Number(item.exitCode || 0) !== 0 || Boolean(item.error);
const validationErrors = (validation.failed || 0) + (exitFailed && !validation.failed ? 1 : 0);
const failed = (prepared.cleaning_errors || 0) + validationErrors;

return {
  json: {
    total: validation.total || 0,
    passed: validation.passed || 0,
    failed,
    has_failures: failed > 0,
    json_files: prepared.local_json_files?.length || 0,
    all_keys: prepared.all_keys || [],
    image_keys: prepared.image_keys || []
  }
};
